import { UsosDialog } from "../dialog";

let dialogElement: UsosDialog | undefined = undefined;

function insertTitle(title?: string) {
    if (title) {
        const titleElement = document.createElement('span');
        titleElement.slot = 'title';
        titleElement.textContent = title;
        dialogElement?.appendChild(titleElement);
    }
}

export async function openDialog(hrefOrContent: string | HTMLElement, title?: string): Promise<UsosDialog> {
    if (dialogElement === undefined) {
        dialogElement = document.createElement('usos-dialog');
        document.body.appendChild(dialogElement);
    }
    if (!dialogElement.hasUpdated) {
        // await for first update that is completed without retriggering
        while (!await dialogElement.updateComplete) {}
    }
    // we can assume that dialog is now created successfully, so fill its contents
    if (typeof hrefOrContent === 'string') {
        dialogElement.dynamic = true;
        dialogElement.url = hrefOrContent;
        dialogElement.open();
        return new Promise(resolve => {
            dialogElement!.addEventListener('dialog:urlLoaded', () => {
                insertTitle(title);
                resolve(dialogElement!);
            }, { once: true });
        });
    } else {
        dialogElement.dynamic = false;
        dialogElement.innerHTML = '';
        dialogElement.appendChild(hrefOrContent);
        insertTitle(title);
        dialogElement.open();
        return dialogElement;
    }
}
